/**
 * SMS notification adapter.
 *
 * Implements NotificationAdapter for the 'sms' channel.
 * Formats the notification payload as a text message and sends it via
 * an SmsTransport abstraction so the actual SMS provider (Twilio, SNS, etc.)
 * can be swapped without changing this adapter.
 *
 * NOTE: The user preferences model (src/models/user-preferences.ts) currently
 * only supports email settings. SMS preferences (enabled, subscribed categories)
 * need to be added to UserPreferences and PreferencesService before SMS
 * notifications can be preference-gated. See the warning posted to Twining.
 */

import type {
  NotificationAdapter,
  NotificationChannel,
  NotificationPayload,
  NotificationResult,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * A rendered SMS message ready for delivery.
 */
export interface SmsMessage {
  to: string;
  body: string;
}

/**
 * Record of a sent SMS, stored for observability and testing.
 */
export interface SentSms {
  to: string;
  body: string;
  sentAt: Date;
}

/**
 * Abstraction for the actual SMS sending mechanism.
 * Implement this to integrate with a real SMS provider (Twilio, AWS SNS, etc.).
 */
export interface SmsTransport {
  sendSms(message: SmsMessage): Promise<{ messageId: string }>;
}

/**
 * Default in-memory transport for development and testing.
 * Stores sent messages in an array for inspection.
 */
export class InMemorySmsTransport implements SmsTransport {
  private sent: SentSms[] = [];

  async sendSms(message: SmsMessage): Promise<{ messageId: string }> {
    this.sent.push({ ...message, sentAt: new Date() });
    const messageId = `sms-${Date.now()}-${this.sent.length}`;
    return { messageId };
  }

  getSentMessages(): SentSms[] {
    return [...this.sent];
  }

  clear(): void {
    this.sent = [];
  }
}

/**
 * SMS configuration options.
 */
export interface SmsAdapterConfig {
  fromNumber: string;
  transport?: SmsTransport;
}

const DEFAULT_CONFIG: SmsAdapterConfig = {
  fromNumber: '+10000000000',
};

/**
 * Validate that a phone number looks like E.164 format.
 * Accepts a leading '+' followed by 7–15 digits.
 */
function isValidPhoneNumber(phone: string): boolean {
  return /^\+[1-9]\d{6,14}$/.test(phone);
}

/**
 * SMS message templates keyed by notification type.
 * SMS messages are kept short — no HTML, no subject line.
 */
const SMS_TEMPLATES: Record<NotificationType, (payload: NotificationPayload) => string> = {
  order_confirmation: (p) => {
    const orderId = (p.metadata?.orderId as string) ?? '';
    return `TaskFlow Pro: Order ${orderId} confirmed. ${p.body}`;
  },
  order_status_update: (p) => {
    const orderId = (p.metadata?.orderId as string) ?? '';
    const newStatus = (p.metadata?.newStatus as string) ?? '';
    return `TaskFlow Pro: Order ${orderId} is now ${newStatus}.`;
  },
  welcome: (p) => {
    return `Welcome to TaskFlow Pro! ${p.body}`;
  },
  account_updated: (p) => {
    return `TaskFlow Pro: ${p.body}`;
  },
};

export class SmsAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'sms';
  private logger = new Logger('SmsAdapter');
  private config: SmsAdapterConfig;
  private transport: SmsTransport;

  constructor(config?: Partial<SmsAdapterConfig>) {
    this.config = { ...DEFAULT_CONFIG, ...config };
    this.transport = this.config.transport ?? new InMemorySmsTransport();
  }

  /**
   * Validate that the recipient looks like a valid phone number.
   */
  private validateRecipient(recipient: string): boolean {
    return isValidPhoneNumber(recipient);
  }

  /**
   * Render a notification payload into an SMS text message using the appropriate template.
   */
  renderMessage(payload: NotificationPayload): string {
    const template = SMS_TEMPLATES[payload.type];
    return template(payload);
  }

  /**
   * Send a notification via SMS.
   * Validates the recipient phone number, renders the message, and delivers via transport.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    if (!this.validateRecipient(payload.recipient)) {
      this.logger.warn(`Invalid SMS recipient: ${payload.recipient}`);
      return {
        success: false,
        notificationId: '',
        channel: this.channel,
        error: `Invalid phone number: ${payload.recipient}`,
      };
    }

    const body = this.renderMessage(payload);
    this.logger.info(`Sending SMS to ${payload.recipient}`);

    try {
      const result = await this.transport.sendSms({ to: payload.recipient, body });
      this.logger.info(`SMS sent successfully: ${result.messageId}`);

      return {
        success: true,
        notificationId: '',
        channel: this.channel,
      };
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : String(err);
      this.logger.error(`Failed to send SMS to ${payload.recipient}: ${errorMessage}`);

      return {
        success: false,
        notificationId: '',
        channel: this.channel,
        error: `SMS delivery failed: ${errorMessage}`,
      };
    }
  }

  /**
   * Get the underlying transport (useful for testing with InMemorySmsTransport).
   */
  getTransport(): SmsTransport {
    return this.transport;
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import {
  SmsAdapter,
  InMemorySmsTransport,
} from '../../src/adapters/sms.adapter.js';
import type {
  SmsTransport,
  SmsMessage,
} from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    recipient: '+15551234567',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    channel: 'sms',
    type: 'order_confirmation',
    metadata: { orderId: 'order-1', userId: 'user-1' },
    ...overrides,
  };
}

describe('SmsAdapter', () => {
  let adapter: SmsAdapter;
  let transport: InMemorySmsTransport;

  beforeEach(() => {
    transport = new InMemorySmsTransport();
    adapter = new SmsAdapter({ transport });
  });

  describe('channel', () => {
    it('should report sms channel', () => {
      expect(adapter.channel).toBe('sms');
    });
  });

  describe('renderMessage', () => {
    it('should render order_confirmation template', () => {
      const payload = makePayload();
      const message = adapter.renderMessage(payload);

      expect(message).toContain('Order');
      expect(message).toContain('order-1');
      expect(message).toContain('TaskFlow Pro');
    });

    it('should render order_status_update template', () => {
      const payload = makePayload({
        type: 'order_status_update',
        body: 'Your order status has changed.',
        metadata: { orderId: 'order-1', newStatus: 'shipped' },
      });

      const message = adapter.renderMessage(payload);
      expect(message).toContain('order-1');
      expect(message).toContain('shipped');
    });

    it('should render welcome template', () => {
      const payload = makePayload({
        type: 'welcome',
        body: 'Hi Alice, welcome!',
      });

      const message = adapter.renderMessage(payload);
      expect(message).toContain('Welcome to TaskFlow Pro');
      expect(message).toContain('Hi Alice');
    });

    it('should render account_updated template', () => {
      const payload = makePayload({
        type: 'account_updated',
        body: 'Your account settings have been updated.',
      });

      const message = adapter.renderMessage(payload);
      expect(message).toContain('TaskFlow Pro');
      expect(message).toContain('account settings have been updated');
    });
  });

  describe('recipient validation', () => {
    it('should reject invalid phone numbers', async () => {
      const payload = makePayload({ recipient: 'not-a-phone' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
    });

    it('should reject phone numbers without + prefix', async () => {
      const payload = makePayload({ recipient: '15551234567' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
    });

    it('should reject phone numbers that are too short', async () => {
      const payload = makePayload({ recipient: '+12345' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
    });

    it('should reject empty recipient', async () => {
      const payload = makePayload({ recipient: '' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
    });

    it('should accept valid E.164 phone numbers', async () => {
      const payload = makePayload({ recipient: '+15551234567' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
    });

    it('should accept international phone numbers', async () => {
      const payload = makePayload({ recipient: '+447911123456' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
    });
  });

  describe('send', () => {
    it('should send SMS via transport and return success', async () => {
      const payload = makePayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.channel).toBe('sms');

      const sent = transport.getSentMessages();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('+15551234567');
      expect(sent[0]?.body).toContain('order-1');
    });

    it('should handle transport errors gracefully', async () => {
      const failingTransport: SmsTransport = {
        sendSms: async () => {
          throw new Error('SMS service unavailable');
        },
      };
      const failAdapter = new SmsAdapter({ transport: failingTransport });

      const payload = makePayload();
      const result = await failAdapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('SMS service unavailable');
    });

    it('should handle non-Error throw from transport', async () => {
      const failingTransport: SmsTransport = {
        sendSms: async () => {
          throw 'string error';
        },
      };
      const failAdapter = new SmsAdapter({ transport: failingTransport });

      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('string error');
    });

    it('should send multiple messages independently', async () => {
      await adapter.send(makePayload({ recipient: '+15551234567' }));
      await adapter.send(makePayload({ recipient: '+15559876543' }));

      const sent = transport.getSentMessages();
      expect(sent).toHaveLength(2);
      expect(sent[0]?.to).toBe('+15551234567');
      expect(sent[1]?.to).toBe('+15559876543');
    });
  });

  describe('configuration', () => {
    it('should use default config when none provided', () => {
      const defaultAdapter = new SmsAdapter({ transport });
      expect(defaultAdapter.channel).toBe('sms');
    });

    it('should allow custom from number', () => {
      const customAdapter = new SmsAdapter({
        fromNumber: '+18005551234',
        transport,
      });
      expect(customAdapter.channel).toBe('sms');
    });
  });
});

describe('InMemorySmsTransport', () => {
  let transport: InMemorySmsTransport;

  beforeEach(() => {
    transport = new InMemorySmsTransport();
  });

  it('should store sent messages', async () => {
    const message: SmsMessage = {
      to: '+15551234567',
      body: 'Test message',
    };

    const result = await transport.sendSms(message);
    expect(result.messageId).toBeTruthy();

    const sent = transport.getSentMessages();
    expect(sent).toHaveLength(1);
    expect(sent[0]?.to).toBe('+15551234567');
    expect(sent[0]?.sentAt).toBeInstanceOf(Date);
  });

  it('should clear sent messages', async () => {
    await transport.sendSms({ to: '+15551234567', body: 'Test' });

    transport.clear();
    expect(transport.getSentMessages()).toHaveLength(0);
  });

  it('should return unique message IDs', async () => {
    const message: SmsMessage = { to: '+15551234567', body: 'Test' };

    const r1 = await transport.sendSms(message);
    const r2 = await transport.sendSms(message);
    expect(r1.messageId).not.toBe(r2.messageId);
  });
});

